import pandas as pd,numpy as np,json
from build_solution import load_annotations,FEATURES,CATS
from xgboost import XGBClassifier
from sklearn.metrics import roc_auc_score,average_precision_score,brier_score_loss
parts=[]
for p,a in [('clinvar_train_sample.parquet','clinvar_train_myvariant.jsonl'),('clinvar_general_sample.parquet','clinvar_general_myvariant.jsonl')]:
 z=pd.concat([pd.read_parquet(p).reset_index(drop=True),load_annotations(a)],axis=1);parts.append(z)
t=pd.concat(parts,ignore_index=True);t['key']=t.chrom.astype(str)+':'+t.pos.astype(str)+':'+t.ref+':'+t.alt;t=t.drop_duplicates('key',keep='last').reset_index(drop=True)
y=t.label.astype(str).str.lower().eq('pathogenic').astype(int);va=t.chrom.astype(str).isin({'1','4','7','10','13','16','19','22','X'})
params=dict(n_estimators=450,max_depth=3,learning_rate=.04,min_child_weight=8,subsample=.85,colsample_bytree=.9,reg_lambda=4,n_jobs=8,random_state=1729,eval_metric='logloss')
report={}
for name,fs in [('cadd_only',['cadd_raw','cadd_phred']),('cadd_consequence_af',['cadd_raw','cadd_phred','af']+CATS),('full',FEATURES)]:
 m=XGBClassifier(**params).fit(t.loc[~va,fs],y[~va]);p=m.predict_proba(t.loc[va,fs])[:,1]
 report[name]={'auroc':float(roc_auc_score(y[va],p)),'auprc':float(average_precision_score(y[va],p)),'brier':float(brier_score_loss(y[va],p))}
 if name=='full':
  slices={}
  for cat in CATS:
   q=va&(t[cat]>0)
   if q.sum()>=30 and y[q].nunique()==2:
    slices[cat]={'n':int(q.sum()),'auroc':float(roc_auc_score(y[q],p[t.loc[va,cat].to_numpy()>0]))}
  report['full_slices']=slices
open('iteration_metrics.json','w').write(json.dumps(report,indent=2));print(json.dumps(report,indent=2))
PY"

